export const 入山符丙二 = (bi) => {
    const u = bi.u;
    const k = 1.05;
    const X = (c) => (c - 12.3) * k;
    const Z = (r) => (r - 1.0) * k;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 星 = (c, r, 半 = 0.5) => bi.dot(X(c), Z(r), 半);
    // 目箱（桁列夾雙括）
    const 目 = (x0, x1, z0, 桁, 括 = true) => {
        for (const z of 桁)
            線(p => p.M(X(x0), Z(z)).L(X(x1), Z(z - 0.2)), 0.55);
        if (括) {
            出(p => p.M(X(x0), Z(桁[0] + 0.3)).C(X(x0 - 0.4), Z((桁[0] + 桁[桁.length - 1]) / 2), X(x0 - 0.3), Z(桁[桁.length - 1] - 0.4), X(x0 + 0.1), Z(桁[桁.length - 1] + 0.2)), 0.5);
            出(p => p.M(X(x1), Z(桁[0] + 0.1)).C(X(x1 + 0.4), Z((桁[0] + 桁[桁.length - 1]) / 2), X(x1 + 0.3), Z(桁[桁.length - 1] - 0.5), X(x1 - 0.1), Z(桁[桁.length - 1])), 0.5);
        }
    };
    // ── 左柱 ──
    目(6.7, 11.7, 2.0, [2.1, 3.1, 4.1]);
    目(6.6, 11.8, 5.0, [5.6, 6.5, 7.4, 8.4]);
    線(p => p.M(X(7.0), Z(9.2)).L(X(11.3), Z(9.0)), 0.5);
    // 厂桁長垂
    線(p => p.M(X(6.6), Z(10.2)).L(X(11.6), Z(10.0)), 0.6);
    出(p => p.M(X(6.6), Z(10.3)).C(X(6.4), Z(17.0), X(6.6), Z(24.0), X(6.3), Z(29.0))
        .C(X(6.1), Z(30.5), X(5.6), Z(31.6), X(4.9), Z(32.3)), 0.65);
    // 日框四桁
    目(8.1, 11.8, 16.8, [16.9, 18.0, 19.1, 20.2]);
    // 連珠星陣：人字鏈
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.5 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)), 0.42);
    };
    星(10.1, 20.9);
    星(8.4, 21.8);
    星(11.7, 21.9);
    連([10.1, 20.9], [8.4, 21.8]);
    連([10.1, 20.9], [11.7, 21.9]);
    // 工字鏈
    星(8.5, 23.2);
    星(10.0, 23.0);
    星(11.8, 23.3);
    星(8.4, 24.6);
    星(11.7, 24.7);
    連([8.5, 23.2], [10.0, 23.0]);
    連([10.0, 23.0], [11.8, 23.3]);
    連([8.5, 23.2], [8.4, 24.6]);
    連([11.8, 23.3], [11.7, 24.7]);
    // 菱陣
    星(10.3, 26.0);
    星(8.6, 27.4);
    星(11.9, 27.5);
    星(10.4, 28.9);
    連([10.3, 26.0], [8.6, 27.4]);
    連([10.3, 26.0], [11.9, 27.5]);
    連([8.6, 27.4], [10.4, 28.9]);
    連([11.9, 27.5], [10.4, 28.9]);
    // ── 右柱 ──
    目(13.6, 18.4, 1.6, [1.7, 2.8, 3.9]);
    目(13.5, 18.3, 4.9, [5.5, 6.4, 7.3, 8.3]);
    線(p => p.M(X(14.0), Z(9.7)).L(X(17.9), Z(9.5)), 0.5);
    // 冂桁長垂
    線(p => p.M(X(13.7), Z(11.2)).L(X(18.3), Z(11.0)), 0.6);
    出(p => p.M(X(18.3), Z(11.1)).C(X(18.4), Z(17.5), X(18.2), Z(24.0), X(18.5), Z(29.0))
        .C(X(18.6), Z(30.5), X(19.0), Z(31.6), X(19.6), Z(32.3)), 0.65);
    // 人峰（大三角，雙坡重描）
    出(p => p.M(X(15.7), Z(12.6)).C(X(14.9), Z(14.4), X(14.0), Z(16.2), X(13.2), Z(17.9)), 0.65);
    出(p => p.M(X(15.7), Z(12.7)).C(X(16.3), Z(14.1), X(16.8), Z(15.5), X(17.2), Z(16.8)), 0.65);
    出(p => p.M(X(15.5), Z(14.2)).C(X(15.0), Z(15.4), X(14.5), Z(16.6), X(14.0), Z(17.8)), 0.5);
    // 峰下川流
    出(p => p.M(X(14.3), Z(16.4)).C(X(13.7), Z(18.2), X(14.4), Z(20.0), X(13.8), Z(21.6)), 0.5);
    出(p => p.M(X(15.6), Z(17.0)).C(X(15.0), Z(18.7), X(15.7), Z(20.3), X(15.2), Z(21.9)), 0.5);
    出(p => p.M(X(16.7), Z(17.4)).C(X(16.3), Z(18.8), X(16.8), Z(20.1), X(16.4), Z(21.4)), 0.5);
    // 弓曲鏈垂迴（幅張）
    出(p => p.M(X(15.9), Z(22.2))
        .C(X(14.6), Z(23.0), X(14.6), Z(24.2), X(15.8), Z(24.6))
        .C(X(16.9), Z(25.0), X(16.9), Z(26.2), X(15.7), Z(26.6))
        .C(X(14.6), Z(27.0), X(14.6), Z(28.2), X(15.7), Z(28.5))
        .C(X(16.5), Z(28.8), X(16.5), Z(29.6), X(15.8), Z(30.0)), 0.55);
    // 底巛小曲
    出(p => p.M(X(14.3), Z(28.9)).C(X(14.0), Z(29.5), X(14.2), Z(30.0), X(14.7), Z(30.2)), 0.45);
    出(p => p.M(X(15.8), Z(29.2)).C(X(15.5), Z(29.8), X(15.7), Z(30.3), X(16.2), Z(30.5)), 0.45);
};
